using UnityEngine;

/// <summary>
/// Tarefa #31 — coordena transições entre áreas/cenas: recebe pedidos de
/// <see cref="AreaTransition"/>, pede a <see cref="SceneLoader"/> para
/// carregar a cena da área de destino (AreaData.sceneName) e, depois de
/// carregada, reposiciona o player no <see cref="AreaSpawnPoint"/> indicado
/// e actualiza WorldState/PlayerProgress — mesma lógica de
/// <see cref="CameraAreaBounds"/> (marca a área como visitada e dispara
/// autosave ao mudar de área).
///
/// Mantém o player (GameObject com tag "Player") persistente entre cenas
/// (DontDestroyOnLoad) — sem isto, SceneManager.LoadSceneAsync (modo Single,
/// usado por LoadingScreenController) destruiria o player ao trocar de cena.
///
/// Singleton com auto-fallback (mesmo padrão de outros managers — Tarefa #15,
/// ver PlayerProgress.cs para a explicação completa).
/// </summary>
public class AreaManager : MonoBehaviour
{
    public static AreaManager Instance { get; private set; }

    private bool isAutoFallback;
    private GameObject playerRoot;
    private bool transitionPending;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(AreaManager) + " (Fallback)");
        var instance = go.AddComponent<AreaManager>();
        instance.isAutoFallback = true;
    }

    /// <summary>true enquanto uma transição de área (pedido + carregamento de cena) estiver em curso — AreaTransition deve ignorar novos pedidos.</summary>
    public bool TransitionPending => transitionPending || (SceneLoader.Instance != null && SceneLoader.Instance.IsLoading);

    /// <summary>
    /// Chamado por <see cref="WorldMapEntryPoint"/> imediatamente antes de
    /// abrir o Terra de Gaia (cena do mapa-múndi). Garante que o player
    /// sobrevive à troca de cena em modo Single (DontDestroyOnLoad) e cancela
    /// quaisquer habilidades com estado — sem isto, o player era destruído ao
    /// carregar a cena do mapa e ficava indisponível ao regressar.
    /// </summary>
    public void PrepareForMapOpen()
    {
        EnsurePlayerPersistent();

        if (playerRoot != null)
            playerRoot.GetComponent<AbilityRouter>()?.CancelAll(AbilityCancelReason.SceneLoad);
    }

    /// <summary>
    /// Pede a troca para a cena de "targetArea" (AreaData.sceneName),
    /// reaparecendo no AreaSpawnPoint "targetSpawnPointId" dessa cena. Sem
    /// efeito se já houver uma transição em curso, se "targetArea"/
    /// "targetArea.sceneName" forem inválidos, ou se SceneLoader não existir.
    /// </summary>
    public void RequestTransition(AreaData targetArea, string targetSpawnPointId)
    {
        if (TransitionPending) return;
        if (targetArea == null || string.IsNullOrEmpty(targetArea.sceneName)) return;
        if (SceneLoader.Instance == null) return;

        EnsurePlayerPersistent();

        // Interrompe habilidades "com estado" (planar, escudo, carregar
        // objecto, camuflagem, balanço, escalada, investida, língua, ...)
        // antes de trocar de cena — sem isto, o estado/efeitos de movimento
        // (gravidade alterada, locks, etc.) eram transportados para a área
        // de destino. Mesmo padrão de PlayerDeathHandler/FormSwitcher.
        if (playerRoot != null)
            playerRoot.GetComponent<AbilityRouter>()?.CancelAll(AbilityCancelReason.SceneLoad);

        transitionPending = true;
        SceneLoader.Instance.LoadArea(targetArea, () => OnAreaSceneLoaded(targetArea, targetSpawnPointId));
    }

    /// <summary>
    /// Garante que o player (tag "Player") sobrevive à troca de cena
    /// (DontDestroyOnLoad) — chamado antes do primeiro LoadArea. Sem efeito
    /// se já estiver persistente ou se nenhum objecto com tag "Player" for
    /// encontrado.
    /// </summary>
    private void EnsurePlayerPersistent()
    {
        if (playerRoot != null) return;

        var playerT = PlayerLocator.Find();
        if (playerT == null) return;

        playerRoot = playerT.root.gameObject;
        playerRoot.transform.SetParent(null);
        DontDestroyOnLoad(playerRoot);
    }

    /// <summary>
    /// Chamado por SceneLoader depois da cena de "area" activar: reposiciona
    /// o player no AreaSpawnPoint "spawnPointId" (se existir nessa cena) e
    /// actualiza WorldState.CurrentArea/PlayerProgress (área visitada +
    /// autosave em mudanças reais de área), tal como CameraAreaBounds faz ao
    /// entrar numa área pela primeira vez.
    /// </summary>
    private void OnAreaSceneLoaded(AreaData area, string spawnPointId)
    {
        if (playerRoot != null)
        {
            var spawn = FindSpawnPoint(spawnPointId);
            if (spawn != null)
            {
                var rb = playerRoot.GetComponent<Rigidbody2D>();
                if (rb != null)
                {
                    rb.position = spawn.transform.position;
                    rb.linearVelocity = Vector2.zero;
                }
                else
                {
                    playerRoot.transform.position = spawn.transform.position;
                }

                // Garante que câmara/triggers vêem já a posição nova neste
                // frame (mesmo padrão de SaveManager.RestoreState).
                Physics2D.SyncTransforms();
            }
            else if (!string.IsNullOrEmpty(spawnPointId))
            {
                Debug.LogWarning($"[AreaManager] AreaSpawnPoint '{spawnPointId}' não encontrado na cena '{area.sceneName}'.");
            }
        }

        // Re-liga a câmara da nova cena ao player persistente — sem isto, a
        // CameraManager da cena recém-carregada não segue o player (o campo
        // "player" do Inspector está vazio/aponta para um player antigo
        // destruído, e SetPlayer nunca era chamado por ninguém).
        if (playerRoot != null)
            CameraManager.Instance?.SetPlayer(playerRoot.transform);

        bool areaChanged = WorldState.Instance != null && WorldState.Instance.SetCurrentArea(area);
        PlayerProgress.Instance?.MarkVisited(area);

        // Autosave ao mudar de área (mesma lógica de CameraAreaBounds — cobre
        // também "entrar/sair de uma cidade", já que isso é sempre uma
        // mudança de área).
        if (areaChanged) SaveManager.Instance?.SaveAutosave();

        transitionPending = false;
    }

    private static AreaSpawnPoint FindSpawnPoint(string spawnId)
    {
        if (string.IsNullOrEmpty(spawnId)) return null;

        var points = FindObjectsByType<AreaSpawnPoint>(FindObjectsSortMode.None);
        foreach (var point in points)
        {
            if (point != null && point.spawnId == spawnId) return point;
        }

        return null;
    }
}
